import { 菩薩坐身, 上臂常勢, 前臂 } from './pusa.js';
import { 杵 } from '../bujian/sanmaya.js';
import { 側拳, 臂釧, 腕釧 } from '../bujian/index.js';
export const 文殊師利菩薩 = (bi) => 菩薩坐身(bi, {
    月輪: false,
    冠: '無',
    髻: '五髻',
    嚴先: true,
    臂(bi, 筆) {
        const { M, L, C, Qk, S, 骨, 衣, 細, 陰, 陽 } = 筆;
        骨(() => { 上臂常勢(筆, -1, 40.0); 上臂常勢(筆, 1, 40.2); });
        // 尊左：執蓮莖，蓮上橫五鈷杵
        衣(() => {
            M(6.5, 41.6);
            C(6.2, 38.8, 6.0, 36.2, 5.9, 33.9);
            S();
            M(7.2, 41.5);
            C(6.95, 38.8, 6.85, 36.2, 6.8, 33.9);
            S();
            M(4.5, 33.9);
            Qk(5.1, 32.5, 5.9, 32.1);
            S();
            M(8.2, 33.85);
            Qk(7.7, 32.55, 6.95, 32.1);
            S();
            M(5.9, 32.1);
            Qk(6.4, 31.9, 6.95, 32.1);
            S();
        });
        杵(bi, 6.35, 30.8, 0.52, 5, 0, 2.7, 0.95);
        骨(() => 陰(() => 前臂(bi, 筆, [13.8, 40.3], [8.8, 41.9], { 寬根: 2.5, 寬梢: 1.9, 弓: -0.35, 肘帽: true })));
        側拳(bi, 6.8, 41.6, -0.25, 1.06, -1);
        // 尊右：持經卷（橫卷當胸，拳自下托執）
        骨(() => 陽(() => 前臂(bi, 筆, [-13.7, 40.1], [-6.9, 38.6], { 寬根: 2.5, 寬梢: 1.9, 弓: 0.4, 肘帽: true })));
        衣(() => {
            // 經卷：橫函雙緣，兩端見軸，束帶居中
            M(-7.9, 34.3);
            L(-3.3, 34.7);
            S();
            M(-7.9, 35.5);
            L(-3.3, 35.9);
            S();
            bi.E(-8.0, 34.9, 0.3, 0.62, 0.08);
            bi.E(-3.2, 35.3, 0.3, 0.62, 0.08);
            細(() => {
                M(-5.85, 34.5);
                L(-5.8, 35.75);
                S();
                M(-5.45, 34.53);
                L(-5.4, 35.78);
                S();
                bi.dot(-8.0, 34.9, 0.1);
                bi.dot(-3.2, 35.3, 0.1);
            });
        });
        側拳(bi, -5.6, 37.5, 1.35, 1.05);
        // 嚴
        臂釧(bi, -1, 12.1, 14.5, 33.4);
        臂釧(bi, 1, 12.1, 14.5, 33.4);
        細(() => {
            腕釧(bi, [[-8.4, 37.6, -7.7, 38.4, -7.0, 39.2], [-7.9, 37.0, -7.2, 37.8, -6.5, 38.6]], [-7.5, 38.0]);
            腕釧(bi, [[9.8, 40.8, 9.3, 41.9, 9.8, 43.1], [10.7, 41.0, 10.2, 42.1, 10.7, 43.3]], [10.4, 42.1]);
        });
    },
});
